" CDS Table Function wrapping AMDP for Fiori/OData
define table function ZTF_INVENTORY_AGING
  with parameters p_plant : werks_d
  returns {
    matnr    : matnr;
    werks    : werks_d;
    stock_qty: menge;
    age_days : int4;
    age_bucket: char10;
  }
  implemented by method
    ZCL_INV_AMDP=>GET_AGING;

